action_status = #{actionStatus}, current_location_id = #{currentLocationId}, tote_id = #{toteId}, status = #{status}, completed_at = #{completedAt}, tote_scanned_at = #{toteScannedAt}, location_scanned_at = #{locationScannedAt}
